import React, { useRef, useEffect, useState, useCallback } from 'react';

const API_BASE = '/api';

/**
 * GraphView — D3.js力学モデルによる知識グラフ可視化
 * ノードをドラッグ、ズーム、ホバーでテキスト表示
 */
export default function GraphView() {
  const svgRef = useRef(null);
  const [graphData, setGraphData] = useState(null);
  const [selectedNode, setSelectedNode] = useState(null);
  const [error, setError] = useState('');
  const simRef = useRef(null);

  // グラフデータ取得
  const fetchGraph = useCallback(async () => {
    try {
      const res = await fetch(`${API_BASE}/graph/data`);
      if (res.ok) {
        const data = await res.json();
        setGraphData(data);
        setError('');
      } else {
        setError('グラフデータの取得に失敗しました');
      }
    } catch (e) {
      setError(`接続エラー: ${e.message}`);
    }
  }, []);

  useEffect(() => { fetchGraph(); }, [fetchGraph]);

  // D3シミュレーション
  useEffect(() => {
    if (!graphData || !svgRef.current) return;
    if (graphData.nodes.length === 0) return;

    const svg = svgRef.current;
    const width = svg.clientWidth;
    const height = svg.clientHeight;

    // 前回のシミュレーションを停止
    if (simRef.current) simRef.current.stop();

    // ノードとリンクのディープコピー（D3が変更するため）
    const nodes = graphData.nodes.map(n => ({ ...n }));
    const links = graphData.edges.map(e => ({
      source: typeof e.source === 'object' ? e.source.id : e.source,
      target: typeof e.target === 'object' ? e.target.id : e.target,
      relation: e.relation,
    }));

    // SVGをクリア
    while (svg.firstChild) svg.removeChild(svg.firstChild);

    // ズーム用グループ
    const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    svg.appendChild(g);

    // ズーム＆パン
    let transform = { x: 0, y: 0, k: 1 };
    let isPanning = false;
    let startX, startY;

    svg.addEventListener('mousedown', (e) => {
      if (e.target === svg) {
        isPanning = true;
        startX = e.clientX - transform.x;
        startY = e.clientY - transform.y;
      }
    });
    svg.addEventListener('mousemove', (e) => {
      if (isPanning) {
        transform.x = e.clientX - startX;
        transform.y = e.clientY - startY;
        g.setAttribute('transform', `translate(${transform.x},${transform.y}) scale(${transform.k})`);
      }
    });
    svg.addEventListener('mouseup', () => { isPanning = false; });
    svg.addEventListener('mouseleave', () => { isPanning = false; });

    svg.addEventListener('wheel', (e) => {
      e.preventDefault();
      const delta = e.deltaY > 0 ? 0.9 : 1.1;
      transform.k = Math.max(0.1, Math.min(5, transform.k * delta));
      const rect = svg.getBoundingClientRect();
      const mx = e.clientX - rect.left;
      const my = e.clientY - rect.top;
      transform.x = mx - (mx - transform.x) * delta;
      transform.y = my - (my - transform.y) * delta;
      g.setAttribute('transform', `translate(${transform.x},${transform.y}) scale(${transform.k})`);
    });

    // リンク描画
    const linkElements = links.map(link => {
      const line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
      line.setAttribute('stroke', link.relation === 'shared_entity' ? '#f59e0b' : '#ccc');
      line.setAttribute('stroke-width', link.relation === 'shared_entity' ? '1.5' : '1');
      line.setAttribute('stroke-opacity', '0.6');
      g.appendChild(line);
      return { el: line, data: link };
    });

    // ノード描画
    const nodeElements = nodes.map(node => {
      const group = document.createElementNS('http://www.w3.org/2000/svg', 'g');
      group.style.cursor = 'pointer';

      const circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      const r = Math.max(6, Math.min(20, 4 + node.degree * 2));
      circle.setAttribute('r', r);
      circle.setAttribute('fill', node.color);
      circle.setAttribute('stroke', '#fff');
      circle.setAttribute('stroke-width', '1.5');
      group.appendChild(circle);

      // ラベル（短め）
      const text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
      text.textContent = node.label.slice(0, 15) + (node.label.length > 15 ? '…' : '');
      text.setAttribute('x', r + 4);
      text.setAttribute('y', 4);
      text.setAttribute('font-size', '11');
      text.setAttribute('fill', '#555');
      text.setAttribute('font-family', '"Segoe UI", "Meiryo", sans-serif');
      group.appendChild(text);

      // ホバーイベント
      group.addEventListener('mouseenter', () => {
        circle.setAttribute('stroke', '#2563eb');
        circle.setAttribute('stroke-width', '3');
        setSelectedNode(node);
      });
      group.addEventListener('mouseleave', () => {
        circle.setAttribute('stroke', '#fff');
        circle.setAttribute('stroke-width', '1.5');
      });
      group.addEventListener('click', () => {
        setSelectedNode(node);
      });

      // ドラッグ
      let dragging = false;
      group.addEventListener('mousedown', (e) => {
        dragging = true;
        node.fx = node.x;
        node.fy = node.y;
        e.stopPropagation();
      });
      window.addEventListener('mousemove', (e) => {
        if (dragging) {
          const rect = svg.getBoundingClientRect();
          node.fx = (e.clientX - rect.left - transform.x) / transform.k;
          node.fy = (e.clientY - rect.top - transform.y) / transform.k;
          sim.alpha(0.3).restart();
        }
      });
      window.addEventListener('mouseup', () => {
        if (dragging) {
          dragging = false;
          node.fx = null;
          node.fy = null;
        }
      });

      g.appendChild(group);
      return { el: group, data: node, circle };
    });

    // 力学シミュレーション（簡易版 — D3不使用）
    const sim = {
      alpha: function(a) { this._alpha = a; return this; },
      restart: function() { this._running = true; },
      stop: function() { this._running = false; },
      _alpha: 1,
      _running: true,
    };
    simRef.current = sim;

    // 初期位置をランダム配置
    nodes.forEach(n => {
      n.x = width / 2 + (Math.random() - 0.5) * 300;
      n.y = height / 2 + (Math.random() - 0.5) * 300;
      n.vx = 0;
      n.vy = 0;
    });

    // nodeMapを作成
    const nodeMap = {};
    nodes.forEach(n => { nodeMap[n.id] = n; });

    // リンクのsource/targetをノードオブジェクトに解決
    links.forEach(link => {
      link.sourceNode = nodeMap[link.source];
      link.targetNode = nodeMap[link.target];
    });

    function tick() {
      if (!sim._running) return;

      // 斥力（ノード間反発）
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const a = nodes[i], b = nodes[j];
          let dx = b.x - a.x, dy = b.y - a.y;
          let dist = Math.sqrt(dx * dx + dy * dy) || 1;
          let force = -300 / (dist * dist);
          let fx = dx / dist * force, fy = dy / dist * force;
          a.vx += fx; a.vy += fy;
          b.vx -= fx; b.vy -= fy;
        }
      }

      // 引力（リンク）
      links.forEach(link => {
        const s = link.sourceNode, t = link.targetNode;
        if (!s || !t) return;
        let dx = t.x - s.x, dy = t.y - s.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;
        let force = (dist - 80) * 0.01;
        let fx = dx / dist * force, fy = dy / dist * force;
        s.vx += fx; s.vy += fy;
        t.vx -= fx; t.vy -= fy;
      });

      // 中心引力
      nodes.forEach(n => {
        n.vx += (width / 2 - n.x) * 0.001;
        n.vy += (height / 2 - n.y) * 0.001;
      });

      // 位置更新
      nodes.forEach(n => {
        if (n.fx != null) { n.x = n.fx; n.vx = 0; }
        else { n.vx *= 0.85; n.x += n.vx; }
        if (n.fy != null) { n.y = n.fy; n.vy = 0; }
        else { n.vy *= 0.85; n.y += n.vy; }
      });

      // DOM更新
      linkElements.forEach(({ el, data }) => {
        const s = nodeMap[data.source] || nodeMap[data.source?.id];
        const t = nodeMap[data.target] || nodeMap[data.target?.id];
        if (s && t) {
          el.setAttribute('x1', s.x); el.setAttribute('y1', s.y);
          el.setAttribute('x2', t.x); el.setAttribute('y2', t.y);
        }
      });

      nodeElements.forEach(({ el, data }) => {
        el.setAttribute('transform', `translate(${data.x},${data.y})`);
      });

      sim._alpha *= 0.99;
      if (sim._alpha > 0.001) {
        requestAnimationFrame(tick);
      }
    }

    requestAnimationFrame(tick);

    return () => { sim.stop(); };
  }, [graphData]);

  if (error) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center',
        height: '100%', color: '#dc2626', fontSize: 14 }}>
        {error}
      </div>
    );
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center',
        justifyContent: 'center', height: '100%', color: '#999' }}>
        <p style={{ fontSize: 16, marginBottom: 8 }}>グラフが空です</p>
        <p style={{ fontSize: 13 }}>サイドバーからドキュメントを追加してください</p>
      </div>
    );
  }

  return (
    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
      {/* グラフSVG */}
      <svg
        ref={svgRef}
        style={{ width: '100%', height: '100%', background: '#fafafa' }}
      />

      {/* 凡例 */}
      <div style={{
        position: 'absolute', top: 12, left: 12, background: '#fff',
        border: '1px solid #e0e0e0', borderRadius: 8, padding: '8px 12px',
        fontSize: 11, color: '#666',
      }}>
        <div style={{ fontWeight: 600, marginBottom: 4 }}>コミュニティ</div>
        {Object.entries(graphData.communities).map(([id, info]) => (
          <div key={id} style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 2 }}>
            <span style={{
              width: 10, height: 10, borderRadius: '50%', background: info.color,
              display: 'inline-block',
            }} />
            <span>{id} ({info.count})</span>
          </div>
        ))}
        <div style={{ marginTop: 6, borderTop: '1px solid #eee', paddingTop: 4, color: '#aaa' }}>
          ドラッグ: ノード移動<br/>
          スクロール: ズーム<br/>
          背景ドラッグ: パン
        </div>
      </div>

      {/* 操作ボタン */}
      <div style={{ position: 'absolute', top: 12, right: 12, display: 'flex', gap: 6 }}>
        <button
          onClick={fetchGraph}
          style={{
            padding: '6px 12px', background: '#fff', border: '1px solid #d0d0d0',
            borderRadius: 6, cursor: 'pointer', fontSize: 12,
          }}
        >
          更新
        </button>
      </div>

      {/* 選択ノード詳細 */}
      {selectedNode && (
        <div style={{
          position: 'absolute', bottom: 12, left: 12, right: 12,
          background: '#fff', border: '1px solid #e0e0e0', borderRadius: 8,
          padding: 12, maxHeight: 150, overflowY: 'auto',
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <span style={{
                width: 12, height: 12, borderRadius: '50%', background: selectedNode.color,
                display: 'inline-block',
              }} />
              <span style={{ fontWeight: 600, fontSize: 13 }}>{selectedNode.community}</span>
              <span style={{ fontSize: 11, color: '#999' }}>接続: {selectedNode.degree}</span>
            </div>
            <button
              onClick={() => setSelectedNode(null)}
              style={{
                background: 'none', border: 'none', cursor: 'pointer',
                fontSize: 16, color: '#999', padding: '0 4px',
              }}
            >
              ×
            </button>
          </div>
          <p style={{ fontSize: 12, color: '#444', marginTop: 6, lineHeight: 1.5 }}>
            {selectedNode.text}
          </p>
        </div>
      )}
    </div>
  );
}
